using namespace std;

class FenwickTree {
    vector<long long> tree;
    int size;
public:
    FenwickTree(int n) : size(n), tree(n + 2, 0) {}
    void update(int index, long long delta) {
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }
    long long query(int index) {
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

long long compute_depth(long long x) {
    long long depth = 0;
    while (x != 1) {
        x = __builtin_popcountll(x);
        depth++;
    }
    return depth;
}

